import { useState, useEffect, useCallback } from 'react';
import { collegesAPI } from '../api';

const STREAMS  = ['All','Engineering','Medical','Management','Arts','Science'];
const BUDGETS  = [['Any',''],['Under ₹1L','1L'],['₹1–3L','3L'],['₹3–8L','8L'],['₹8L+','8Lplus']];
const RATINGS  = [['Any Rating',''],['4.5+','4.5'],['4.0+','4.0'],['3.5+','3.5']];
const SORT_OPTS= [['Best Match','match'],['Highest Rating','rating'],['Lowest Fees','fees'],['Best Package','package'],['NIRF Rank','nirf']];

export default function CollegeFinder() {
  const [colleges, setColleges] = useState([]);
  const [total,    setTotal]    = useState(0);
  const [loading,  setLoading]  = useState(false);
  const [page,     setPage]     = useState(1);
  const [states,   setStates]   = useState([]);

  const [filters, setFilters] = useState({
    search:'', stream:'All', state:'', budget:'', rating:'', sort:'match', p12: '', page:1
  });

  const setF = (k, v) => setFilters(f => ({ ...f, [k]: v, page: 1 }));

  // Load states once
  useEffect(() => {
    collegesAPI.getStates().then(s => setStates(['All States', ...s])).catch(()=>{});
  }, []);

  const fetchColleges = useCallback(async () => {
    setLoading(true);
    try {
      const params = {};
      if (filters.search) params.search = filters.search;
      if (filters.stream && filters.stream !== 'All') params.stream = filters.stream;
      if (filters.state  && filters.state  !== 'All States') params.state = filters.state;
      if (filters.budget) params.budget = filters.budget;
      if (filters.rating) params.rating = filters.rating;
      if (filters.sort)   params.sort   = filters.sort;
      if (filters.p12)    params.p12    = filters.p12;
      params.page = filters.page;
      params.per  = 20;

      const data = await collegesAPI.getAll(params);
      setColleges(data.colleges);
      setTotal(data.total);
    } catch {
      // Fallback to static data if backend not running
      const { COLLEGES } = await import('../data');
      setColleges(COLLEGES);
      setTotal(COLLEGES.length);
    }
    setLoading(false);
  }, [filters]);

  useEffect(() => { fetchColleges(); }, [fetchColleges]);

  const reset = () => setFilters({ search:'', stream:'All', state:'', budget:'', rating:'', sort:'match', p12:'', page:1 });

  return (
    <div className="page-wrapper animate-in">
      <div className="page-header">
        <div className="page-header-left">
          <h1 className="page-title">🏛️ College Finder</h1>
          <p className="page-subtitle">{total} colleges · Search, filter & compare across India</p>
        </div>
        <span className="badge badge-success">● {total} results</span>
      </div>

      {/* Filter Card */}
      <div className="card mb-24">
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(150px,1fr))', gap:12, marginBottom:12 }}>
          <div className="form-group" style={{ gridColumn:'span 2' }}>
            <label className="form-label">🔍 Search</label>
            <input className="form-input" placeholder="College name or city…" value={filters.search} onChange={e=>setF('search',e.target.value)} />
          </div>
          <div className="form-group">
            <label className="form-label">Stream</label>
            <select className="form-select" value={filters.stream} onChange={e=>setF('stream',e.target.value)}>
              {STREAMS.map(s=><option key={s}>{s}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">State</label>
            <select className="form-select" value={filters.state} onChange={e=>setF('state',e.target.value)}>
              {states.map(s=><option key={s}>{s}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Budget/yr</label>
            <select className="form-select" value={filters.budget} onChange={e=>setF('budget',e.target.value)}>
              {BUDGETS.map(([l,v])=><option key={v} value={v}>{l}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Min Rating</label>
            <select className="form-select" value={filters.rating} onChange={e=>setF('rating',e.target.value)}>
              {RATINGS.map(([l,v])=><option key={v} value={v}>{l}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Sort By</label>
            <select className="form-select" value={filters.sort} onChange={e=>setF('sort',e.target.value)}>
              {SORT_OPTS.map(([l,v])=><option key={v} value={v}>{l}</option>)}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Your 12th %</label>
            <input className="form-input" type="number" placeholder="e.g. 88" value={filters.p12} onChange={e=>setF('p12',e.target.value)} />
          </div>
        </div>
        <div className="flex gap-8">
          <button className="btn btn-primary btn-sm" onClick={fetchColleges}>Apply Filters</button>
          <button className="btn btn-ghost btn-sm" onClick={reset}>Reset All</button>
        </div>
      </div>

      {/* Loading */}
      {loading && (
        <div style={{ textAlign:'center', padding:'40px 0', color:'var(--text-muted)' }}>
          <div style={{ fontSize:32, marginBottom:12 }}>⏳</div>
          Searching colleges…
        </div>
      )}

      {/* College Grid */}
      {!loading && (
        <div className="grid-2" style={{ gap:16 }}>
          {colleges.map((c, i) => (
            <div key={c.id || i} className="college-card">
              <div className="college-card-header">
                <div>
                  <div className="college-name">{c.name}</div>
                  <div className="college-loc">📍 {c.location || c.loc}</div>
                  {c.nirf_rank && <div className="text-xs text-muted mt-4">NIRF Rank: #{c.nirf_rank}</div>}
                </div>
                <div style={{ display:'flex', flexDirection:'column', alignItems:'flex-end', gap:6 }}>
                  <span className={`badge ${(c.match||70) >= 80 ? 'badge-success' : (c.match||70) >= 65 ? 'badge-primary' : 'badge-warn'}`}>
                    {c.match || Math.round(c.rating * 18)}% match
                  </span>
                  {c.placement_pct && <span className="badge badge-muted">{c.placement_pct}% placed</span>}
                </div>
              </div>

              <div className="college-stats">
                <div className="college-stat">
                  <div className="college-stat-label">Rating</div>
                  <div className="college-stat-value" style={{ color:'var(--accent-warn)' }}>★ {c.rating}</div>
                </div>
                <div className="college-stat">
                  <div className="college-stat-label">Fees / yr</div>
                  <div className="college-stat-value">{c.fees}</div>
                </div>
                <div className="college-stat">
                  <div className="college-stat-label">Avg Package</div>
                  <div className="college-stat-value" style={{ color:'var(--accent-success)' }}>{c.avg_package || c.placement}</div>
                </div>
                <div className="college-stat">
                  <div className="college-stat-label">Cutoff</div>
                  <div className="college-stat-value" style={{ fontSize:'0.72rem' }}>{c.cutoff_jee || c.cutoff}</div>
                </div>
              </div>

              <div className="flex gap-8" style={{ marginTop:12 }}>
                <button className="btn btn-ghost btn-sm" onClick={()=> c.website && window.open('https://'+c.website,'_blank')}>
                  🌐 Website
                </button>
                <button className="btn btn-success btn-sm">+ Shortlist</button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Pagination */}
      {total > 20 && (
        <div className="flex justify-center gap-8" style={{ marginTop:24 }}>
          <button className="btn btn-ghost btn-sm" disabled={filters.page <= 1} onClick={()=>setF('page', filters.page-1)}>← Prev</button>
          <span style={{ fontSize:'0.82rem', color:'var(--text-muted)', alignSelf:'center' }}>Page {filters.page}</span>
          <button className="btn btn-ghost btn-sm" onClick={()=>setF('page', filters.page+1)}>Next →</button>
        </div>
      )}
    </div>
  );
}
